
.nge-toast-container[data-v-bcd5f0a5] {
  position: fixed;
  top: 52px;
  right: 16px;
  z-index: 9999;
  display: flex;
  flex-direction: column;
  gap: 8px;
  pointer-events: none;
  max-width: 360px;
}

/* ── Toast card ── */
.nge-toast[data-v-bcd5f0a5] {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 16px;
  background: rgba(18, 22, 30, 0.96);
  border: 1px solid rgba(100, 180, 255, 0.2);
  border-radius: 10px;
  box-shadow:
    0 8px 32px rgba(0, 0, 0, 0.5),
    0 0 40px rgba(74, 158, 255, 0.06);
  cursor: pointer;
  pointer-events: all;
  position: relative;
  overflow: hidden;
  backdrop-filter: blur(8px);
}

/* Type-specific accent */
.nge-toast--badge[data-v-bcd5f0a5]  { border-color: rgba(206, 147, 216, 0.3);
}
.nge-toast--streak[data-v-bcd5f0a5] { border-color: rgba(245, 166, 35, 0.3);
}
.nge-toast--cells[data-v-bcd5f0a5]  { border-color: rgba(76, 175, 80, 0.3);
}
.nge-toast--edits[data-v-bcd5f0a5]  { border-color: rgba(74, 158, 255, 0.3);
}
.nge-toast--quest[data-v-bcd5f0a5]  { border-color: rgba(0, 200, 255, 0.35); box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5), 0 0 60px rgba(0, 200, 255, 0.12);
}

/* ── Icon ── */
.nge-toast-icon[data-v-bcd5f0a5] {
  width: 40px;
  height: 40px;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.04);
}
.nge-toast--badge .nge-toast-icon[data-v-bcd5f0a5]  { background: rgba(206, 147, 216, 0.1);
}
.nge-toast--streak .nge-toast-icon[data-v-bcd5f0a5] { background: rgba(245, 166, 35, 0.1);
}
.nge-toast--cells .nge-toast-icon[data-v-bcd5f0a5]  { background: rgba(76, 175, 80, 0.1);
}
.nge-toast--quest .nge-toast-icon[data-v-bcd5f0a5]  { background: rgba(0, 200, 255, 0.12);
}
.nge-toast-badge-img[data-v-bcd5f0a5] {
  width: 32px;
  height: 32px;
  object-fit: contain;
  filter: drop-shadow(0 0 8px rgba(206, 147, 216, 0.5));
  animation: nge-toast-badge-glow-bcd5f0a5 1.5s ease-in-out infinite alternate;
}
@keyframes nge-toast-badge-glow-bcd5f0a5 {
from { filter: drop-shadow(0 0 4px rgba(206, 147, 216, 0.3));
}
to   { filter: drop-shadow(0 0 12px rgba(206, 147, 216, 0.7));
}
}
.nge-toast-emoji[data-v-bcd5f0a5] {
  font-size: 22px;
  line-height: 1;
  animation: nge-toast-bounce-bcd5f0a5 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);
}
@keyframes nge-toast-bounce-bcd5f0a5 {
0%   { transform: scale(0.3); opacity: 0;
}
60%  { transform: scale(1.2);
}
100% { transform: scale(1); opacity: 1;
}
}

/* ── Text ── */
.nge-toast-text[data-v-bcd5f0a5] {
  flex: 1;
  min-width: 0;
}
.nge-toast-title[data-v-bcd5f0a5] {
  font-size: 13px;
  font-weight: 700;
  color: #e0e4ec;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.nge-toast--badge .nge-toast-title[data-v-bcd5f0a5]  { color: #CE93D8;
}
.nge-toast--streak .nge-toast-title[data-v-bcd5f0a5] { color: #f5a623;
}
.nge-toast--cells .nge-toast-title[data-v-bcd5f0a5]  { color: #81C784;
}
.nge-toast--quest .nge-toast-title[data-v-bcd5f0a5]  { color: #00c8ff;
}
.nge-toast-subtitle[data-v-bcd5f0a5] {
  font-size: 11px;
  color: #666;
  margin-top: 2px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

/* ── Progress bar (auto-dismiss) ── */
.nge-toast-progress[data-v-bcd5f0a5] {
  position: absolute;
  bottom: 0;
  left: 0;
  height: 2px;
  background: rgba(74, 158, 255, 0.4);
  animation: nge-toast-countdown-bcd5f0a5 5s linear forwards;
}
.nge-toast--badge .nge-toast-progress[data-v-bcd5f0a5]  { background: rgba(206, 147, 216, 0.4);
}
.nge-toast--streak .nge-toast-progress[data-v-bcd5f0a5] { background: rgba(245, 166, 35, 0.4);
}
.nge-toast--cells .nge-toast-progress[data-v-bcd5f0a5]  { background: rgba(76, 175, 80, 0.4);
}
.nge-toast--quest .nge-toast-progress[data-v-bcd5f0a5]  { background: rgba(0, 200, 255, 0.4);
}
@keyframes nge-toast-countdown-bcd5f0a5 {
from { width: 100%;
}
to   { width: 0%;
}
}

/* ── Sparkle particles ── */
.nge-toast-particles[data-v-bcd5f0a5] {
  position: absolute;
  inset: 0;
  pointer-events: none;
  overflow: hidden;
}
.nge-toast-particle[data-v-bcd5f0a5] {
  position: absolute;
  width: 3px;
  height: 3px;
  border-radius: 50%;
  background: rgba(200, 220, 255, 0.6);
  animation: nge-toast-sparkle-bcd5f0a5 1.2s ease-out forwards;
  animation-delay: calc(var(--i) * 0.08s);
  left: calc(10% + var(--i) * 14%);
  top: 50%;
}
.nge-toast--badge .nge-toast-particle[data-v-bcd5f0a5]  { background: rgba(206, 147, 216, 0.7);
}
.nge-toast--streak .nge-toast-particle[data-v-bcd5f0a5] { background: rgba(245, 166, 35, 0.7);
}
.nge-toast--cells .nge-toast-particle[data-v-bcd5f0a5]  { background: rgba(129, 199, 132, 0.7);
}
.nge-toast--quest .nge-toast-particle[data-v-bcd5f0a5]  { background: rgba(0, 200, 255, 0.7);
}
@keyframes nge-toast-sparkle-bcd5f0a5 {
0%   { opacity: 1; transform: translate(0, 0) scale(1);
}
50%  { opacity: 0.8; transform: translate(calc((var(--i) - 3) * 8px), -20px) scale(0.6);
}
100% { opacity: 0; transform: translate(calc((var(--i) - 3) * 14px), -35px) scale(0);
}
}

/* ── Transitions ── */
.nge-toast-enter-active[data-v-bcd5f0a5] {
  transition: all 0.35s cubic-bezier(0.34, 1.56, 0.64, 1);
}
.nge-toast-leave-active[data-v-bcd5f0a5] {
  transition: all 0.25s ease-in;
}
.nge-toast-enter-from[data-v-bcd5f0a5] {
  opacity: 0;
  transform: translateX(100px) scale(0.8);
}
.nge-toast-leave-to[data-v-bcd5f0a5] {
  opacity: 0;
  transform: translateX(60px) scale(0.9);
}
.nge-toast-move[data-v-bcd5f0a5] {
  transition: transform 0.3s ease;
}
