}
.nge-chat-banner-fade-enter-from[data-v-519c8e58] { opacity: 0; transform: translateX(-50%) translateY(8px);
}
.nge-chat-banner-fade-leave-to[data-v-519c8e58] { opacity: 0; transform: translateX(-50%) translateY(8px);
}

