  position: absolute;
  width: 4px;
  height: 4px;
  border-radius: 50%;
  background: rgba(255, 215, 0, 0.6);
  animation: nge-quest-float-f64e5c3c 3s ease-in-out infinite;
  animation-delay: calc(var(--i) * 0.25s);
  left: calc(var(--i) * 8% + 2%);
  top: 80%;
  box-shadow: 0 0 6px rgba(255, 215, 0, 0.4);
}
.nge-quest-particle[data-v-f64e5c3c]:nth-child(even) {
  background: rgba(180, 140, 255, 0.5);
