  background: rgba(100, 200, 255, 0.5);
  box-shadow: 0 0 6px rgba(100, 200, 255, 0.3);
  width: 5px;
  height: 5px;
}
@keyframes nge-quest-float-f64e5c3c {
0% { transform: translateY(0) scale(0); opacity: 0;
}
10% { opacity: 1; transform: translateY(-10px) scale(1);
