/* ═══════════════════════════════════════════════════════════════════════
   CELL COMPLETION CELEBRATION
   ═══════════════════════════════════════════════════════════════════════ */
.nge-cell-celebration[data-v-f64e5c3c] {
  position: absolute; inset: 0;
  background: radial-gradient(ellipse at center, rgba(0, 40, 80, 0.97), rgba(4, 8, 18, 0.98));
  display: flex; flex-direction: column;
  align-items: center; justify-content: center;
  z-index: 55;
  border-radius: 4px;
  overflow: hidden;
  cursor: pointer;
}

/* Expanding ring pulses */
.nge-cell-celebration-rings[data-v-f64e5c3c] {
  position: absolute; top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  pointer-events: none;
}
.nge-cell-ring[data-v-f64e5c3c] {
  position: absolute;
  border: 2px solid rgba(0, 220, 150, 0.4);
  border-radius: 50%;
  animation: nge-ring-expand-f64e5c3c 2s ease-out infinite;
}
.nge-cell-ring--1[data-v-f64e5c3c] { width: 60px; height: 60px; top: -30px; left: -30px; animation-delay: 0s;
}
.nge-cell-ring--2[data-v-f64e5c3c] { width: 60px; height: 60px; top: -30px; left: -30px; animation-delay: 0.4s;
}
.nge-cell-ring--3[data-v-f64e5c3c] { width: 60px; height: 60px; top: -30px; left: -30px; animation-delay: 0.8s;
}
@keyframes nge-ring-expand-f64e5c3c {
0% { transform: scale(0.5); opacity: 0.8;
}
100% { transform: scale(5); opacity: 0;
}
}

/* Particle burst */
.nge-cell-celebration-burst[data-v-f64e5c3c] {
  position: absolute; top: 50%; left: 50%;
  pointer-events: none;
}
.nge-cell-burst-particle[data-v-f64e5c3c] {
  position: absolute;
  width: 6px; height: 6px;
  border-radius: 50%;
  animation: nge-burst-f64e5c3c 1.4s ease-out forwards;
  animation-delay: calc(var(--i) * 0.03s);
  --angle: calc(var(--i) * 15deg);
  --dist: calc(40px + var(--i) * 6px);
}
.nge-cell-burst-particle[data-v-f64e5c3c]:nth-child(3n+1) { background: #0d9; box-shadow: 0 0 6px #0d9;
}
.nge-cell-burst-particle[data-v-f64e5c3c]:nth-child(3n+2) { background: #fd6; box-shadow: 0 0 6px #fd6;
}
.nge-cell-burst-particle[data-v-f64e5c3c]:nth-child(3n)   { background: #4cf; box-shadow: 0 0 6px #4cf;
}
@keyframes nge-burst-f64e5c3c {
0% { transform: translate(0, 0) scale(1); opacity: 1;
}
100% {
    transform: translate(
      calc(cos(var(--angle)) * var(--dist)),
      calc(sin(var(--angle)) * var(--dist))
    ) scale(0);
    opacity: 0;
}
}
.nge-cell-celebration-badge[data-v-f64e5c3c] {
  font-size: 48px;
  color: #0d9;
  text-shadow: 0 0 30px rgba(0, 221, 153, 0.5), 0 0 60px rgba(0, 221, 153, 0.2);
  animation: nge-badge-pop-f64e5c3c 0.6s cubic-bezier(0.34, 1.56, 0.64, 1) both;
  position: relative;
  z-index: 2;
}
@keyframes nge-badge-pop-f64e5c3c {
0% { transform: scale(0) rotate(-20deg); opacity: 0;
}
60% { transform: scale(1.2) rotate(5deg); opacity: 1;
}
100% { transform: scale(1) rotate(0);
}
}
.nge-cell-celebration-title[data-v-f64e5c3c] {
  font-size: 22px;
  font-weight: 800;
  color: #fff;
  margin-top: 8px;
  letter-spacing: 1px;
  text-shadow: 0 0 20px rgba(0, 180, 255, 0.3);
