  position: relative; z-index: 2;
}
@keyframes nge-title-slide-f64e5c3c {
0% { transform: translateY(10px); opacity: 0;
}
100% { transform: translateY(0); opacity: 1;
}
}
.nge-cell-celebration-name[data-v-f64e5c3c] {
  font-size: 15px;
  font-weight: 600;
  color: #0d9;
  margin-top: 4px;
