  background: rgba(0, 221, 153, 0.2);
  transform: translateY(-1px);
}

/* Cell celebration transitions */
.nge-cell-celebrate-enter-active[data-v-f64e5c3c] { transition: all 0.4s ease-out;
}
.nge-cell-celebrate-leave-active[data-v-f64e5c3c] { transition: all 0.3s ease-in;
